#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int x1,y1,x2,y2; scanf("%d %d %d %d", &x1, &y1, &x2, &y2);
        int dx = abs(x1 - x2);
        int dy = abs(y1 - y2);
        int ans = dx > dy ? dx : dy;
        printf("%d\n", ans);
    }
    return 0;
}

